components.css:
.ds-button-primary {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.85rem 2rem;
  border-radius: 999px;
  background: #e8222e;
  color: #ffffff;
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  text-decoration: none;
  box-shadow: 0 4px 20px rgba(232, 34, 46, 0.28);
  transition: background-color 0.25s ease, box-shadow 0.25s ease, transform 0.25s ease;
}
.ds-button-primary:hover {
  background: #b81820;
  box-shadow: 0 8px 30px rgba(232, 34, 46, 0.38);
  transform: translateY(-2px);
}
.ds-button-primary:focus-visible {
  outline: 2px solid #b81820;
  outline-offset: 2px;
}

.ds-button-outline {
  display: inline-flex;
  align-items: center;
  padding: 0.85rem 2rem;
  border-radius: 999px;
  border: 1.5px solid rgba(0, 0, 0, 0.08);
  background: transparent;
  color: #111111;
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  text-decoration: none;
  transition: border-color 0.25s ease, color 0.25s ease, transform 0.25s ease;
}
.ds-button-outline:hover {
  border-color: #e8222e;
  color: #e8222e;
  transform: translateY(-2px);
}
.ds-button-outline:focus-visible {
  outline: 2px solid #e8222e;
  outline-offset: 2px;
}

.ds-kontakt-demo {
  background: #e8222e;
  padding: 2rem;
  border-radius: 16px;
}
.ds-button-white {
  display: inline-flex;
  align-items: center;
  padding: 0.9rem 2.25rem;
  border-radius: 999px;
  background: #ffffff;
  color: #e8222e;
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  font-weight: 800;
  text-decoration: none;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12);
  transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.ds-button-white:hover {
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.18);
  transform: translateY(-2px);
}
.ds-button-white:focus-visible {
  outline: 2px solid #ffffff;
  outline-offset: 2px;
}

.ds-badge {
  display: inline-flex;
  align-items: center;
  padding: 0.3rem 0.9rem;
  border-radius: 999px;
  background: rgba(232, 34, 46, 0.09);
  border: 1px solid rgba(232, 34, 46, 0.2);
  color: #e8222e;
  font-family: 'Outfit', sans-serif;
  font-size: 0.72rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.ds-chip {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.6rem 1rem;
  border-radius: 10px;
  background: #ffffff;
  border: 1.5px solid rgba(0, 0, 0, 0.08);
  box-shadow: 0 4px 18px rgba(0, 0, 0, 0.07);
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.67rem;
  color: #111111;
  animation: ds-chip-float 7s ease-in-out infinite;
}
.ds-chip-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #e8222e;
  animation: ds-dot-blink 2.5s ease-in-out infinite;
}
@keyframes ds-chip-float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}
@keyframes ds-dot-blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.25; }
}
@media (prefers-reduced-motion: reduce) {
  .ds-chip, .ds-chip-dot { animation: none; }
}

.ds-card-service {
  background: #f0ede8;
  border: 1.5px solid rgba(0, 0, 0, 0.08);
  border-radius: 16px;
  padding: 1.75rem 2rem;
  transition: border-color 0.3s ease, box-shadow 0.3s ease, transform 0.3s ease;
}
.ds-card-service:hover {
  border-color: rgba(232, 34, 46, 0.35);
  box-shadow: 0 12px 40px rgba(232, 34, 46, 0.08);
  transform: translateY(-4px);
}
.ds-card-icon {
  width: 44px;
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  background: rgba(232, 34, 46, 0.09);
  margin-bottom: 1rem;
}
.ds-card-title {
  font-family: 'Outfit', sans-serif;
  font-size: 1.15rem;
  font-weight: 800;
  letter-spacing: -0.03em;
  color: #111111;
  margin: 0 0 0.5rem;
}
.ds-card-body {
  font-family: 'Outfit', sans-serif;
  font-size: 0.95rem;
  line-height: 1.7;
  color: #666666;
  margin: 0;
}

.ds-card-stat {
  background: #ffffff;
  border: 1.5px solid rgba(0, 0, 0, 0.08);
  border-radius: 16px;
  padding: 1.75rem;
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  transition: border-color 0.3s ease, transform 0.3s ease;
}
.ds-card-stat:hover {
  border-color: rgba(232, 34, 46, 0.35);
  transform: translateY(-4px);
}
.ds-stat-number {
  font-family: 'Outfit', sans-serif;
  font-size: 2.4rem;
  font-weight: 900;
  letter-spacing: -0.04em;
  color: #111111;
}
.ds-stat-label {
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  font-weight: 600;
  color: #666666;
}

.ds-nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 68px;
  padding: 0 1.5rem;
  background: rgba(249, 247, 244, 0.92);
  backdrop-filter: blur(20px) saturate(1.4);
  border-bottom: 1.5px solid rgba(0, 0, 0, 0.05);
}
.ds-nav-logo {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  font-family: 'Outfit', sans-serif;
  font-weight: 900;
  font-size: 1.15rem;
  letter-spacing: -0.04em;
  color: #111111;
}
.ds-nav-logo-accent { color: #e8222e; }
.ds-nav-city {
  font-family: 'Outfit', sans-serif;
  font-size: 0.62rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  background: #e8222e;
  color: #ffffff;
  border-radius: 999px;
  padding: 0.2rem 0.6rem;
}
.ds-nav-links {
  display: flex;
  align-items: center;
  gap: 1.75rem;
}
.ds-nav-links a:not(.ds-nav-cta) {
  font-family: 'Outfit', sans-serif;
  font-size: 0.9rem;
  font-weight: 600;
  color: #666666;
  text-decoration: none;
  transition: color 0.2s ease;
}
.ds-nav-links a:not(.ds-nav-cta):hover { color: #111111; }
.ds-nav-cta {
  padding: 0.55rem 1.3rem;
  font-size: 0.85rem;
  box-shadow: 0 2px 12px rgba(232, 34, 46, 0.25);
}
.ds-nav-cta:hover {
  box-shadow: 0 4px 18px rgba(232, 34, 46, 0.35);
}
@media (max-width: 900px) {
  .ds-nav-links a:not(.ds-nav-cta) { display: none; }
}
